#include <stdio.h>
#include <stdlib.h>

int cmp_asc(const void *a, const void *b) { return (*(int*)a) - (*(int*)b); }
int cmp_desc(const void *a, const void *b) { return (*(int*)b) - (*(int*)a); }

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        int *B = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        for(int i=0;i<N;i++) scanf("%d", &B[i]);
        qsort(A, N, sizeof(int), cmp_asc);
        qsort(B, N, sizeof(int), cmp_desc);
        long long low = 2, high = 2000000000LL, ans = 2;
        int need = N/2 + 1;
        while(low <= high){
            long long mid = (low + high) >> 1;
            int cnt = 0;
            for(int i=0;i<N;i++) if((long long)A[i] + B[i] >= mid) cnt++;
            if(cnt >= need){ ans = mid; low = mid + 1; }
            else high = mid - 1;
        }
        printf("%lld\n", ans);
        free(A); free(B);
    }
    return 0;
}

