import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] A = new long[N];
            long[] B = new long[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextLong();
            for (int i = 0; i < N; i++) B[i] = fs.nextLong();
            Arrays.sort(A);
            Arrays.sort(B);
            // reverse B in place
            for (int i = 0; i < N / 2; i++) {
                long tmp = B[i];
                B[i] = B[N - 1 - i];
                B[N - 1 - i] = tmp;
            }
            long low = 2, high = 2000000000L, ans = 2;
            int need = N / 2 + 1;
            while (low <= high) {
                long mid = (low + high) >>> 1;
                int cnt = 0;
                for (int i = 0; i < N; i++) if (A[i] + B[i] >= mid) cnt++;
                if (cnt >= need) { ans = mid; low = mid + 1; }
                else high = mid - 1;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

